<template>
	<view :class="['container', isDark ? 'dark-mode' : '']">
		<button class="btn-primary" @tap="showForm = !showForm">
			{{ showForm ? t('vote.hideForm') : '+ ' + t('vote.toggleForm') }}
		</button>

		<view v-if="showForm" class="card form-card">
			<view class="form-title">{{ t('vote.formTitle') }}</view>
			<input class="input" v-model="form.title" :placeholder="t('vote.topicPh')" />
			<view v-for="(opt, idx) in form.options" :key="idx" class="option-row">
				<input
					class="input option-input"
					v-model="form.options[idx]"
					:placeholder="t('vote.optionPh') + ' ' + (idx + 1)"
				/>
				<text
					v-if="form.options.length > 2"
					class="option-del"
					@tap="removeOption(idx)"
				>✕</text>
			</view>
			<view class="option-actions">
				<text class="add-option" @tap="addOption">+ {{ t('vote.addOption') }}</text>
			</view>
			<button class="btn-primary" @tap="submitVote">{{ t('vote.submit') }}</button>
		</view>

		<view class="section-title">{{ t('vote.list') }}</view>
		<view v-if="voteList.length === 0" class="empty-tip">
			<text>{{ t('vote.noVote') }}</text>
		</view>
		<view v-for="(vote, index) in voteList" :key="index" class="card vote-item">
			<view class="vote-header">
				<text class="vote-title">{{ vote.title }}</text>
				<text :class="['vote-status', vote.status === 'active' ? 'active' : 'ended']">
					{{ vote.status === 'active' ? t('vote.active') : t('vote.ended') }}
				</text>
			</view>
			<view
				v-for="(opt, oi) in vote.options"
				:key="oi"
				class="vote-option"
				@tap="doVote(index, oi)"
			>
				<view class="option-bar">
					<view class="option-fill" :style="{ width: getPercent(vote, oi) + '%' }"></view>
				</view>
				<view class="option-info">
					<text>{{ opt.label }}</text>
					<text class="option-count">{{ opt.count }} {{ t('vote.ticket') }} ({{ getPercent(vote, oi) }}%)</text>
				</view>
			</view>
			<text class="vote-time">{{ vote.createTime }}</text>
		</view>
	</view>
</template>

<script setup>
/**
 * 投票管理页
 * - 展示投票列表，支持投票操作
 * - 发起新投票（含动态选项）
 */
import { ref, reactive, onMounted } from 'vue'
import { onShow } from '@dcloudio/uni-app'
import { get, post } from '@/utils/request'
import { t } from '@/utils/i18n'
import { isDark, applyNavBarTheme } from '@/utils/theme'

// 控制表单显示
const showForm = ref(false)

// 新投票表单
const form = reactive({
	title: '',
	options: ['', '']
})

// 投票列表（模拟数据）
const voteList = ref([
	{
		title: '周末聚餐选哪家？',
		status: 'active',
		options: [
			{ label: '火锅', count: 2 },
			{ label: '烧烤', count: 1 },
			{ label: '日料', count: 0 }
		],
		createTime: '2025-06-05'
	},
	{
		title: '空调温度设定',
		status: 'ended',
		options: [
			{ label: '24°C', count: 3 },
			{ label: '26°C', count: 1 }
		],
		createTime: '2025-05-28'
	}
])

/** 添加选项 */
const addOption = () => {
	if (form.options.length >= 6) {
		uni.showToast({ title: t('vote.maxOption'), icon: 'none' })
		return
	}
	form.options.push('')
}

/** 删除选项 */
const removeOption = (idx) => {
	form.options.splice(idx, 1)
}

/**
 * 计算某选项的投票百分比
 */
const getPercent = (vote, optIndex) => {
	const total = vote.options.reduce((sum, o) => sum + o.count, 0)
	if (total === 0) return 0
	return Math.round((vote.options[optIndex].count / total) * 100)
}

/**
 * 投票操作
 */
const doVote = (voteIndex, optIndex) => {
	const vote = voteList.value[voteIndex]
	if (vote.status !== 'active') {
		uni.showToast({ title: t('vote.voteEnded'), icon: 'none' })
		return
	}
	vote.options[optIndex].count++
	uni.showToast({ title: t('vote.voteSuccess'), icon: 'success' })
}

/**
 * 提交新投票
 */
const submitVote = async () => {
	if (!form.title) {
		uni.showToast({ title: t('vote.topicRequired'), icon: 'none' })
		return
	}
	const validOptions = form.options.filter(o => o.trim() !== '')
	if (validOptions.length < 2) {
		uni.showToast({ title: t('vote.minOption'), icon: 'none' })
		return
	}

	const newVote = {
		title: form.title,
		status: 'active',
		options: validOptions.map(label => ({ label, count: 0 })),
		createTime: new Date().toISOString().slice(0, 10)
	}

	// TODO: 调用后端接口
	// await post('/api/vote', newVote)

	voteList.value.unshift(newVote)

	// 重置表单
	form.title = ''
	form.options = ['', '']
	showForm.value = false

	uni.showToast({ title: t('vote.created'), icon: 'success' })
}

onShow(() => {
	applyNavBarTheme()
	uni.setNavigationBarTitle({ title: t('vote.title') })
})

onMounted(async () => {
	try {
		// TODO: 从后端获取投票列表
		// const res = await get('/api/vote/list')
		// voteList.value = res.data
	} catch (e) {
		console.log('获取投票列表失败', e)
	}
})
</script>

